from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    if not triples:
        return ""
    # Use the subject of the first triple as the main entity
    main_subject = triples[0].subject

    # Helper to turn a predicate/object pair into a readable clause
    def clause(pred: str, obj: str) -> str:
        pred = pred.strip()
        obj = obj.strip().strip('"')
        # Expanded lexicalisations for many predicates
        if pred == "cityServed":
            return f"serves the city of {obj}"
        if pred == "location":
            return f"is located in {obj}"
        if pred == "country":
            return f"is in {obj}"
        if pred == "isPartOf":
            return f"is part of {obj}"
        if pred == "owner":
            return f"is owned by {obj}"
        if pred == "operatingOrganisation":
            return f"is operated by {obj}"
        if pred == "elevationAboveTheSeaLevel":
            return f"is at an elevation of {obj} metres above sea level"
        if pred == "elevationAboveTheSeaLevelInFeet":
            return f"is at an elevation of {obj} feet above sea level"
        if pred == "elevationAboveTheSeaLevelInMetres":
            return f"is at an elevation of {obj} metres above sea level"
        if pred == "runwayLength":
            return f"has a runway length of {obj} metres"
        if pred == "runwayName":
            return f"has runway {obj}"
        if pred == "runwaySurfaceType":
            return f"has a runway surface of {obj}"
        if pred.endswith("Identifier"):
            return f"has identifier {obj}"
        if pred.endswith("LengthFeet"):
            return f"has a runway length of {obj} feet"
        if pred.endswith("LengthMetre"):
            return f"has a runway length of {obj} metres"
        if pred.endswith("RunwayNumber"):
            return f"has runway number {obj}"
        if pred.endswith("RunwaySurfaceType"):
            return f"has runway surface type {obj}"
        if pred == "capital":
            return f"has capital {obj}"
        if pred == "largestCity":
            return f"has largest city {obj}"
        if pred == "mayor":
            return f"has mayor {obj}"
        if pred == "leader":
            return f"is led by {obj}"
        if pred == "leaderParty":
            return f"belongs to the party {obj}"
        # Generic fallback
        return f"{pred.replace('_', ' ')} {obj}"

    # Helper to format numbers with commas and remove trailing .0
    def _fmt_num(val: str) -> str:
        try:
            # try integer first
            i = int(float(val))
            return f"{i:,}"
        except Exception:
            return val

    # Build a fluent sentence, merging consecutive triples when the object of one
    # is the subject of the next (e.g., location → country)
    parts = []
    i = 0
    while i < len(triples):
        cur = triples[i]
        cur_obj = cur.object.strip().strip('"')
        cur_clause = clause(cur.predicate, cur.object)

        # Look ahead to see if we can chain with a relative clause
        if i + 1 < len(triples):
            nxt = triples[i + 1]
            if cur_obj == nxt.subject:
                # Combine with a relative “which …” clause
                nxt_clause = clause(nxt.predicate, nxt.object)
                cur_clause = f"{cur_clause}, which {nxt_clause}"
                i += 1  # skip the next triple because it is merged

        parts.append(cur_clause)
        i += 1

    # Assemble the final sentence
    if not parts:
        sentence = ""
    elif len(parts) == 1:
        sentence = f"{main_subject} {parts[0]}."
    else:
        sentence = f"{main_subject} " + ", ".join(parts[:-1]) + f", and {parts[-1]}."
    return sentence

# EVOLVE-BLOCK-END
